import React from "react";
import EMSDLogo from "../../assets/emsd_logo.png";
import { Image, Menu } from "semantic-ui-react";
import { Auth } from "../../api";
import { useLocation } from "react-router";
import { NavLink } from "react-router-dom";
import "./menu-bar.css";

const MenuBar = () => {
  const { pathname } = useLocation();
  const fullUrl = pathname ? pathname.split("/") : "";
  const currentPath = fullUrl.length > 1 ? fullUrl[1] : "";
  return (
    <div>
      <EMSDBar />
      <Menu
        pointing
        secondary
        style={{ display: "flex", textDecoration: "none", textAlign: "center" }}
      >
        <Menu.Item
          as={NavLink}
          to="/dashboard"
          name="Home"
          active={currentPath === ""}
        />
        <Menu.Item
          as={NavLink}
          to="/about-me"
          name="About Mike"
          active={currentPath === "about-me"}
        />
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/projects"
          name="Projects"
          active={currentPath === "projects"}
        />
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/study-with-mike"
          name="Self-Study Blog"
          active={currentPath === "study-with-mike"}
        />
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/contact-mike-right-now"
          name="Contact Me"
          active={currentPath === "contact-me-right-now"}
        />
      </Menu>
    </div>
  );
};

const EMSDBar = () => (
  <div style={{ width: "100%", height: "8em", display: "flex", padding: 24 }}>
    <EMSDLogoContainer />
    <TitleContainer />
    <div
      style={{
        width: 0,
        borderRight: `1px solid #e3e6e9`,
        marginLeft: "1em",
        marginRight: "1em",
      }}
    />
    <ProjectNameContainer />
    <div style={{ flex: 1 }} />
  </div>
);

const EMSDLogoContainer = () => (
  <div
    style={{
      height: "100%",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
    }}
  >
    <Image style={{ marginRight: "1em" }} src={EMSDLogo} alt="EMSD_LOGO" />
  </div>
);

const TitleContainer = () => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      alignItems: "flex-start",
      justifyContent: "center",
    }}
  >
    <h2 style={{ margin: 0, fontSize: 18, fontWeight: "bolder" }}>
      Electrical and Mechanical Services Department
    </h2>
    <h4 style={{ margin: 0, fontSize: 13, fontWeight: 400 }}>
      The Government of the Hong Kong Special Administrative Region
    </h4>
  </div>
);

const ProjectNameContainer = () => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      alignItems: "flex-start",
      justifyContent: "space-evenly",
      fontSize: 22,
      fontWeight: 300,
    }}
  >
    <span>Effective Equipment Maintenance model</span>
    <span>using Artificial Intelligence</span>
  </div>
);

function onSignOut() {
  Auth.signOut();
  localStorage.removeItem("emsd");
}

export default MenuBar;
